// custom button handler
async function compareIncExclHandler() {
    var subcontractText = tinymce.activeEditor.getContent();
    UseComparisonEndpoint = true;
    tinymce.activeEditor.execCommand('mceAiDialog', true | false, {
        prompt: subcontractText,
        generate: true,
        display: false
    });
    UseComparisonEndpoint = false;
}

function stripMarkdownFences(fragment) {
    return fragment
        .replace(/```[a-zA-Z]*\n?/g, '')
        .replace(/```/g, '');
}

function AIChatCompletion(request, respondWith) {
    respondWith.stream((signal, streamMessage) => {
        var subcontractID = <%=Data.SubcontractID %>;
        var endpoint;
        var body = {
            Message: '',
            ModelName: "gpt-4.1-2025-04-14",
            ConversationID: ConversationID || null,
            Stream: true,
        };

        if (UseComparisonEndpoint) {
            body.Message = request.query;
            endpoint = `/SubcontractGenerator/AI/SubcontractComparisonResponse?SubcontractID=${subcontractID}`;
        } else {

            // context is last response - exclude it because we are using conversations w OpenAI
            if (request.context && request.thread[0]?.response?.data || request.context == '') {
                body.Message = request.query;
            } else {
                body.Message = request.prompt;
            }
            endpoint = `/SharedUtil/AI/ChatResponse`;
        }

        const abortController = new AbortController();
        if (signal && signal.addEventListener) {
            signal.addEventListener('abort', () => abortController.abort());
        }

        // Accumulate text so we can optionally throttle updates (optional)
        let accumulated = '';

        function handleSSELine(jsonLine) {
            // Ignore empty / control markers
            if (!jsonLine || jsonLine === '[DONE]') return;

            let obj;
            try {
                obj = JSON.parse(jsonLine);
            } catch {
                // If it's just plain text, append directly
                accumulated += jsonLine;
                streamMessage(jsonLine);
                return;
            }

            // Capture conversation id if present
            if (obj.type === 'response.created' && obj?.response?.conversation?.id) {
                ConversationID = obj?.response?.conversation?.id;
            }

            // OpenAI Responses API streaming:
            // output_text.delta => incremental text chunk
            if (obj.type === 'response.output_text.delta' && typeof obj.delta === 'string') {
                accumulated += obj.delta;
                streamMessage(stripMarkdownFences(obj.delta));
                return;
            }

            // Completion marker
            if (obj.type === 'response.completed') {
                return;
            }

            // Errors
            if (obj.error) {
                throw new Error(obj.error.message || obj.error.type || 'Stream error');
            }
        }

        return fetch(endpoint, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
            signal: abortController.signal
        }).then(response => {
            if (!response.ok) throw new Error('HTTP ' + response.status);

            const ct = response.headers.get('content-type') || '';
            if (!ct.includes('text/event-stream')) {
                // Fallback non-stream
                return response.text().then(t => {
                    try {
                        const j = JSON.parse(t);
                        if (j.error) throw new Error(j.error);
                        let combined = '';
                        if (j.output) {
                            j.output.forEach(o => {
                                (o.content || []).forEach(c => {
                                    if (c.type === 'output_text' && c.text) combined += c.text;
                                });
                            });
                        } else {
                            combined = t;
                        }
                        streamMessage(stripMarkdownFences(combined));
                    } catch {
                        streamMessage(stripMarkdownFences(t));
                    }
                });
            }

            const reader = response.body.getReader();
            const decoder = new TextDecoder('utf-8');
            let buffer = '';

            function processBuffer() {
                // SSE events end with double newline. Split on that.
                const parts = buffer.split(/\r?\n\r?\n/);
                // Keep last part if not finished (partial chunk)
                buffer = parts.pop();
                parts.forEach(part => {
                    part.split(/\r?\n/).forEach(line => {
                        // Only lines starting with data:
                        if (line.startsWith('data:')) {
                            const payload = line.substring(5).trim();
                            handleSSELine(payload);
                        }
                    });
                });
            }

            function read() {
                return reader.read().then(({ done, value }) => {
                    if (done) {
                        processBuffer();
                        return;
                    }
                    buffer += decoder.decode(value, { stream: true });
                    processBuffer();
                    return read();
                });
            }

            return read();
        }).catch(err => {
            throw err;
        });
    });
}

$(function () {
    // setup
    tinymce.init({
        selector: '#<%=txtContent.ClientID %>',
        height: '100%',

        // menu options
        menu: {
            format: {
                title: 'Format',
                items: 'bold italic underline strikethrough | align | language | removeformat',
            }
        },
        toolbar: 'undo redo | bold italic | alignleft aligncenter alignright alignjustify | outdent indent | numlist bullist | aidialog compareIncExclButton',

        // plugins
        plugins: 'table lists ai',

        // ai
        ai_request: AIChatCompletion,

        // setup
        setup: (editor) => {
            editor.ui.registry.addButton('compareIncExclButton', compareIncExclButtonSettings)
        },
    });
});
